 *
 * @param  string $path path
 *
 * @return string
 * @author Troex Nevelin
 **/
protected function _normpath($path)
{
    if (empty($path)) {
        return '.';
    }

    $changeSep = (DIRECTORY_SEPARATOR !== '/');
    if ($changeSep) {
        $drive = '';
        if (preg_match('/^([a-zA-Z]:)(.*)/', $path, $m)) {
